const source = $('Incoming Webhook').first().json.body;
const rawTranscript = $('Transcribe a recording1').first().json.text || '';
const editorResponse = $input.first().json;

const extractResponseText = (payload) => {
  if (!payload) return '';

  if (typeof payload.output_text === 'string' && payload.output_text.trim()) {
    return payload.output_text.trim();
  }

  if (Array.isArray(payload.output)) {
    const chunks = payload.output
      .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
      .map((entry) => entry.text || entry.output_text || '')
      .filter(Boolean);

    if (chunks.length) return chunks.join('\n').trim();
  }

  if (Array.isArray(payload.choices)) {
    const choice = payload.choices[0];
    const content = choice?.message?.content;

    if (typeof content === 'string') return content.trim();

    if (Array.isArray(content)) {
      const chunks = content.map((entry) => entry.text || '').filter(Boolean);
      if (chunks.length) return chunks.join('\n').trim();
    }
  }

  if (typeof payload.text === 'string') {
    return payload.text.trim();
  }

  return '';
};

return [{
  json: {
    sessionId: source.sessionId,
    userId: source.userId,
    fileName: source.fileName,
    mimeType: source.mimeType,
    size: source.size,
    mode: source.mode,
    callbackUrl: source.callbackUrl,
    callbackSecret: source.callbackSecret,
    rawTranscript,
    processedText: extractResponseText(editorResponse),
    status: 'completed',
  },
}];
